import React, { useState } from 'react';
// Note: Si lucide-react n'est pas installé, les icônes ne s'afficheront pas. 
// Tu pourras faire "npm install lucide-react" plus tard.

const App = () => {
  const [currentLevel, setCurrentLevel] = useState(0);
  const [userAnswer, setUserAnswer] = useState('');
  const [feedback, setFeedback] = useState(null);
  const [score, setScore] = useState(0);

  const questions = [
    {
      instruction: "Récupère tous les documents de la collection 'users'.",
      solution: "db.users.find()",
      explanation: "La méthode find() sans filtre retourne tout.",
      schema: "{ _id, name, city }"
    },
    {
      instruction: "Trouve les utilisateurs de 'Vannes'.",
      solution: "db.users.find({city:'Vannes'})",
      explanation: "On utilise un objet { champ: valeur }.",
      schema: "{ _id, name, city }"
    }
  ];

  const currentQ = questions[currentLevel];

  const handleCheck = () => {
    // Nettoyage des espaces pour comparer
    const cleanUser = userAnswer.replace(/\s+/g, '');
    const cleanSol = currentQ.solution.replace(/\s+/g, '');
    
    if (cleanUser === cleanSol) {
      setFeedback('success');
      setScore(score + 10);
    } else {
      setFeedback('error');
    }
  };

  return (
    <div style={{ fontFamily: 'sans-serif', padding: '20px', maxWidth: '800px', margin: 'auto' }}>
      <header style={{ borderBottom: '2px solid #eee', paddingBottom: '10px', marginBottom: '20px' }}>
        <h1 style={{ color: '#00ED64' }}>🍃 MONGOLINGO</h1>
        <p>Score: {score} XP | Question {currentLevel + 1}/{questions.length}</p>
      </header>

      <div style={{ background: 'white', padding: '20px', borderRadius: '15px', border: '2px solid #ddd' }}>
        <h3>{currentQ.instruction}</h3>
        <p style={{ fontSize: '0.8em', color: '#666' }}>Schéma: <code>{currentQ.schema}</code></p>
        
        <textarea 
          style={{ width: '100%', height: '100px', fontFamily: 'monospace', padding: '10px', marginTop: '10px', background: '#1a202c', color: '#00ED64', borderRadius: '8px' }}
          value={userAnswer}
          onChange={(e) => setUserAnswer(e.target.value)}
          placeholder="Tape ta requête ici..."
        />

        <div style={{ marginTop: '20px' }}>
          <button 
            onClick={handleCheck}
            style={{ padding: '10px 20px', background: '#00ED64', border: 'none', borderRadius: '8px', fontWeight: 'bold', cursor: 'pointer' }}
          >
            VÉRIFIER
          </button>

          {feedback === 'success' && (
            <div style={{ color: 'green', marginTop: '10px' }}>
              <b>Bien joué !</b> {currentQ.explanation}
              <button onClick={() => {setCurrentLevel(currentLevel + 1); setFeedback(null); setUserAnswer('')}} style={{ marginLeft: '10px' }}>Suivant</button>
            </div>
          )}
          {feedback === 'error' && <p style={{ color: 'red' }}>Mauvaise réponse, réessaie !</p>}
        </div>
      </div>
    </div>
  );
};

export default App;
